import subprocess,base64,datetime,time,json,os,urllib.request
P1='192.168.10.19'
WEB='/var/www/html'
MSI_WEB='/home/k/vnt-web'
MP='/mnt/vnt-data/FileServer/VNT_World_AI_Division/MemPalace.md'
TSF=datetime.datetime.now().strftime('%Y%m%d_%H%M')

APP_PARTS=[
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
    b'',
]
SW=base64.b64decode(b'')
MANIFEST=base64.b64decode(b'')
ICON192=base64.b64decode(b'')
ICON512=base64.b64decode(b'')
APP=base64.b64decode(b''.join(APP_PARTS))
print(f'Files: app={len(APP)} sw={len(SW)} manifest={len(MANIFEST)}')

def rx(h,c,t=60):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+h,c],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()
def pct_e(id,c,t=120):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=8','root@'+P1,'pct exec '+str(id)+' -- bash -c '+json.dumps(c)],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()
def pct_push(id,local,remote,t=30):
    return rx(P1,f'pct push {id} {local} {remote}',t)
def save(e):
    try: open(MP,'a').write('\n### App Deploy ['+TSF+']\n'+e+'\n')
    except: pass

print('='*55)
print('DEPLOY VNT APP + FIX CT108 502')
print(TSF)
print('='*55)

# ── Fix 502: Restore simple nginx ──
print('[1] Fixing CT108 502...')
st=rx(P1,'pct status 108')
print(' CT108:',st)
if 'stopped' in st.lower():
    rx(P1,'pct start 108',t=20);time.sleep(8)

# Write simple nginx config
nginx_conf='server {\n listen 80;\n server_name vntworld.com www.vntworld.com _;\n root /var/www/html;\n index dashboard.html index.html;\n location / { try_files $uri $uri/ /dashboard.html =404; }\n location /generated/ { alias /var/www/html/generated/; add_header Access-Control-Allow-Origin *; }\n gzip on;\n gzip_types text/html text/css application/javascript;\n client_max_body_size 50M;\n}'
open('/tmp/nginx_fix.conf','w').write(nginx_conf)
pct_push(108,'/tmp/nginx_fix.conf','/etc/nginx/sites-available/default')
pct_e(108,'rm -f /etc/nginx/sites-enabled/* && ln -sf /etc/nginx/sites-available/default /etc/nginx/sites-enabled/default')
test=pct_e(108,'nginx -t 2>&1')
print(' nginx test:',test[:80])
reload=pct_e(108,'systemctl restart nginx 2>/dev/null || service nginx restart 2>/dev/null || nginx -s reload 2>/dev/null')
print(' nginx:',reload[:60])

# ── Check dashboard size - restore if needed ──
print('[2] Dashboard check...')
size_out=pct_e(108,f'stat -c %s {WEB}/dashboard.html 2>/dev/null || wc -c < {WEB}/dashboard.html 2>/dev/null')
try: size=int(size_out.strip().split()[0])
except: size=0
print(f' dashboard.html: {size} bytes')
if size<50000:
    # Try to restore from Prox1 backups
    backups=rx(P1,'ls -t /root/ct108_backups/*.html 2>/dev/null')
    for bk in backups.split('\n'):
        bk=bk.strip()
        if not bk: continue
        bsize_out=rx(P1,f'stat -c %s {bk} 2>/dev/null || wc -c < {bk} 2>/dev/null')
        try: bsize=int(bsize_out.strip().split()[0])
        except: bsize=0
        if bsize>50000:
            rx(P1,f'pct push 108 {bk} {WEB}/dashboard.html',t=30)
            print(f' Restored from {bk}: {bsize} bytes')
            break

# ── Deploy VNT App files to CT108 ──
print('[3] Deploying VNT App to CT108...')
pct_e(108,'mkdir -p /var/www/html/icons /var/www/html/generated /var/www/html/downloads')
# Write app files
for fname,data in [('/tmp/app.html',APP),('/tmp/sw.js',SW),('/tmp/manifest.json',MANIFEST),('/tmp/icon192.png',ICON192),('/tmp/icon512.png',ICON512)]:
    open(fname,'wb').write(data)
pct_push(108,'/tmp/app.html',WEB+'/app.html')
pct_push(108,'/tmp/sw.js',WEB+'/sw.js')
pct_push(108,'/tmp/manifest.json',WEB+'/manifest.json')
pct_push(108,'/tmp/icon192.png',WEB+'/icons/icon-192.png')
pct_push(108,'/tmp/icon512.png',WEB+'/icons/icon-512.png')
print(' App files deployed to CT108')

# ── Also deploy to MSI web ──
print('[4] Deploying to MSI web...')
os.makedirs(MSI_WEB+'/icons',exist_ok=True)
open(MSI_WEB+'/app.html','wb').write(APP)
open(MSI_WEB+'/sw.js','wb').write(SW)
open(MSI_WEB+'/manifest.json','wb').write(MANIFEST)
open(MSI_WEB+'/icons/icon-192.png','wb').write(ICON192)
open(MSI_WEB+'/icons/icon-512.png','wb').write(ICON512)
print(' App deployed to MSI 8888')

# ── Restart portal if needed ──
print('[5] Ensuring MSI portal 8888...')
try: urllib.request.urlopen('http://127.0.0.1:8888/',timeout=4); print(' 8888: already up')
except:
    subprocess.run(['fuser','-k','8888/tcp'],capture_output=True)
    time.sleep(1)
    subprocess.Popen(['/usr/bin/python3',MSI_WEB+'/portal_server.py'],stdout=open('/tmp/portal.log','w'),stderr=subprocess.STDOUT)
    time.sleep(4)
    try: urllib.request.urlopen('http://127.0.0.1:8888/',timeout=4); print(' 8888: started')
    except Exception as e: print(' 8888 failed:',str(e)[:50])

# ── Reload nginx in CT108 ──
pct_e(108,'nginx -s reload 2>/dev/null || true')

# ── Test everything ──
print('[6] Testing all services...')
results={}
tests=[
    ('vntworld.com','http://vntworld.com/dashboard.html'),
    ('vnt-app','http://vntworld.com/app.html'),
    ('MSI-8888','http://127.0.0.1:8888/'),
    ('MSI-app','http://127.0.0.1:8888/app.html'),
    ('Nextcloud','http://192.168.10.10/'),
]
for name,url in tests:
    try:
        with urllib.request.urlopen(url,timeout=8) as r:
            sz=len(r.read())
            results[name]='PASS ('+str(sz)+'b)'
            print(f' {name}: PASS ({sz} bytes)')
    except Exception as e:
        results[name]='FAIL: '+str(e)[:40]
        print(f' {name}: FAIL - {str(e)[:40]}')

# ── Check ADB for phone ──
print('[7] Checking Android device...')
adb_out=subprocess.run('adb devices 2>/dev/null || echo ADB_NOT_FOUND',shell=True,capture_output=True,text=True).stdout.strip()
print(' ADB:',adb_out[:200])
if 'device' in adb_out and 'ADB_NOT_FOUND' not in adb_out:
    # Phone connected - install PWA via ADB
    print(' Phone detected! Pushing app HTML...')
    subprocess.run('adb push /tmp/app.html /sdcard/VNT_App.html 2>/dev/null',shell=True)
    print(' VNT_App.html pushed to phone')

save('App deployed '+TSF+'\nvntworld.com/app.html\n192.168.10.96:8888/app.html\nResults: '+str(results))
print('='*55)
print('DONE')
print('vntworld.com: '+results.get('vntworld.com','?'))
print('VNT App: '+results.get('vnt-app','?'))
